func TestEnumHookTriggerIDEnum(t *testing.T) {
	t.Run("NewFromString_credentials_exchange", func(t *testing.T) {
		t.Parallel()
		val, err := NewHookTriggerIDEnumFromString("credentials-exchange")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, HookTriggerIDEnum("credentials-exchange"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_pre_user_registration", func(t *testing.T) {
		t.Parallel()
		val, err := NewHookTriggerIDEnumFromString("pre-user-registration")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, HookTriggerIDEnum("pre-user-registration"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_post_user_registration", func(t *testing.T) {
		t.Parallel()
		val, err := NewHookTriggerIDEnumFromString("post-user-registration")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, HookTriggerIDEnum("post-user-registration"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_post_change_password", func(t *testing.T) {
		t.Parallel()
		val, err := NewHookTriggerIDEnumFromString("post-change-password")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, HookTriggerIDEnum("post-change-password"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_send_phone_message", func(t *testing.T) {
		t.Parallel()
		val, err := NewHookTriggerIDEnumFromString("send-phone-message")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, HookTriggerIDEnum("send-phone-message"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewHookTriggerIDEnumFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewHookTriggerIDEnumFromString("credentials-exchange")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

